const SENDGRID_API_KEY = 'YOUR_SENDGRID_API_KEY';
const STRIPE_API_KEY = 'YOUR_STRIPE_API_KEY';
const STRIPE_WEBHOOK_SECRET = 'YOUR_STRIPE_WEBHOOK_SECRET';
const ALLOWED_ORIGINS = ['https://yourdomain.com'];

addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request));
});

async function handleRequest(request) {
  const corsHeaders = getCorsHeaders(request);
  
  if (request.method === 'OPTIONS') {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const url = new URL(request.url);
    const path = url.pathname;

    if (path === '/api/send-email' && request.method === 'POST') {
      return await handleSendEmail(request, corsHeaders);
    }
    
    if (path === '/api/create-payment-intent' && request.method === 'POST') {
      return await handleCreatePaymentIntent(request, corsHeaders);
    }
    
    if (path === '/api/create-customer' && request.method === 'POST') {
      return await handleCreateCustomer(request, corsHeaders);
    }
    
    if (path === '/api/stripe-webhook' && request.method === 'POST') {
      return await handleStripeWebhook(request);
    }
    
    if (path === '/api/charge-customer' && request.method === 'POST') {
      return await handleChargeCustomer(request, corsHeaders);
    }

    return jsonResponse({ error: 'Not found' }, 404, corsHeaders);
  } catch (error) {
    return handleError(error, corsHeaders);
  }
}

function getCorsHeaders(request) {
  const origin = request.headers.get('Origin');
  const headers = {
    'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, Authorization',
    'Content-Type': 'application/json',
  };

  if (ALLOWED_ORIGINS.includes(origin)) {
    headers['Access-Control-Allow-Origin'] = origin;
  }

  return headers;
}

async function handleSendEmail(request, corsHeaders) {
  const authHeader = request.headers.get('Authorization');
  if (!validateAuthorization(authHeader)) {
    return jsonResponse({ error: 'Unauthorized' }, 401, corsHeaders);
  }

  const body = await parseJsonBody(request);
  
  if (!body.to || !body.subject || !body.content) {
    return jsonResponse({ 
      error: 'Missing required fields: to, subject, content' 
    }, 400, corsHeaders);
  }

  const emailData = {
    personalizations: [{
      to: [{ email: body.to }],
      subject: body.subject
    }],
    from: { 
      email: body.from || 'noreply@yourdomain.com',
      name: body.fromName || 'Your App'
    },
    content: [{
      type: body.contentType || 'text/html',
      value: body.content
    }]
  };

  if (body.cc) {
    emailData.personalizations[0].cc = [{ email: body.cc }];
  }

  if (body.bcc) {
    emailData.personalizations[0].bcc = [{ email: body.bcc }];
  }

  const sendGridResponse = await fetch('https://api.sendgrid.com/v3/mail/send', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${SENDGRID_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify(emailData)
  });

  if (!sendGridResponse.ok) {
    const errorText = await sendGridResponse.text();
    throw new ApiError(
      `SendGrid API error: ${errorText}`, 
      sendGridResponse.status
    );
  }

  return jsonResponse({ 
    success: true, 
    message: 'Email sent successfully' 
  }, 200, corsHeaders);
}

async function handleCreatePaymentIntent(request, corsHeaders) {
  const authHeader = request.headers.get('Authorization');
  if (!validateAuthorization(authHeader)) {
    return jsonResponse({ error: 'Unauthorized' }, 401, corsHeaders);
  }

  const body = await parseJsonBody(request);
  
  if (!body.amount || !body.currency) {
    return jsonResponse({ 
      error: 'Missing required fields: amount, currency' 
    }, 400, corsHeaders);
  }

  const paymentIntentData = {
    amount: Math.round(body.amount * 100),
    currency: body.currency.toLowerCase(),
    automatic_payment_methods: { enabled: true }
  };

  if (body.customer) {
    paymentIntentData.customer = body.customer;
  }

  if (body.metadata) {
    paymentIntentData.metadata = body.metadata;
  }

  if (body.description) {
    paymentIntentData.description = body.description;
  }

  const stripeResponse = await fetch('https://api.stripe.com/v1/payment_intents', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${STRIPE_API_KEY}`,
      'Content-Type': 'application/x-www-form-urlencoded'
    },
    body: encodeFormData(paymentIntentData)
  });

  const responseData = await stripeResponse.json();

  if (!stripeResponse.ok) {
    throw new ApiError(
      `Stripe API error: ${responseData.error?.message || 'Unknown error'}`,
      stripeResponse.status
    );
  }

  return jsonResponse({ 
    success: true,
    clientSecret: responseData.client_secret,
    paymentIntentId: responseData.id
  }, 200, corsHeaders);
}

