async function handleStripeWebhook(request) {
  const signature = request.headers.get('stripe-signature');
  
  if (!signature) {
    return jsonResponse({ error: 'Missing signature' }, 400);
  }

  const payload = await request.text();
  
  const verified = await verifyStripeSignature(payload, signature, STRIPE_WEBHOOK_SECRET);
  
  if (!verified) {
    return jsonResponse({ error: 'Invalid signature' }, 401);
  }

  const event = JSON.parse(payload);

  switch (event.type) {
    case 'payment_intent.succeeded':
      await handlePaymentIntentSucceeded(event.data.object);
      break;
    case 'payment_intent.payment_failed':
      await handlePaymentIntentFailed(event.data.object);
      break;
    case 'customer.created':
      await handleCustomerCreated(event.data.object);
      break;
    case 'charge.succeeded':
      await handleChargeSucceeded(event.data.object);
      break;
    default:
      console.log(`Unhandled event type: ${event.type}`);
  }

  return jsonResponse({ received: true }, 200);
}

async function verifyStripeSignature(payload, signature, secret) {
  const encoder = new TextEncoder();
  const data = encoder.encode(payload);
  const key = await crypto.subtle.importKey(
    'raw',
    encoder.encode(secret),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['verify']
  );

  const signatureParts = signature.split(',');
  const timestamp = signatureParts.find(p => p.startsWith('t=')).split('=')[1];
  const signatures = signatureParts.filter(p => p.startsWith('v1=')).map(p => p.split('=')[1]);

  const signedPayload = `${timestamp}.${payload}`;
  const expectedSignature = await crypto.subtle.sign(
    'HMAC',
    key,
    encoder.encode(signedPayload)
  );

  const expectedSig = bufferToHex(expectedSignature);
  
  return signatures.some(sig => sig === expectedSig);
}

function bufferToHex(buffer) {
  return Array.from(new Uint8Array(buffer))
    .map(b => b.toString(16).padStart(2, '0'))
    .join('');
}

